15	-------------------------------------------------------------------------------
16	
17	library ieee;
18	use ieee.std_logic_1164.all;
19	use ieee.std_logic_unsigned.all;
20	
21	library surf;
22	use surf.StdRtlPkg.all;
23	
24	entity TrueDualPortRam is
25	   -- MODE_G = {"no-change","read-first","write-first"}
26	   generic (
27	      TPD_G          : time                       := 1 ns;
28	      RST_POLARITY_G : sl                         := '1';  -- '1' for active high rst, '0' for active low
29	      RST_ASYNC_G    : boolean                    := false;
30	      DOA_REG_G      : boolean                    := false;  -- Extra output register on doutA.
31	      DOB_REG_G      : boolean                    := false;  -- Extra output register on doutB.
32	      MODE_G         : string                     := "read-first";
33	      BYTE_WR_EN_G   : boolean                    := false;
34	      DATA_WIDTH_G   : integer range 1 to (2**24) := 18;
35	      BYTE_WIDTH_G   : integer                    := 8;  -- Should be multiple of 8 or 9.
36	      ADDR_WIDTH_G   : integer range 1 to (2**24) := 9;
37	      INIT_G         : slv                        := "0");
38	   port (
39	      -- Port A
40	      clka    : in  sl                                                    := '0';
41	      ena     : in  sl                                                    := '1';
42	      wea     : in  sl                                                    := '0';
43	      weaByte : in  slv(wordCount(DATA_WIDTH_G, BYTE_WIDTH_G)-1 downto 0) := (others => '0');
44	      rsta    : in  sl                                                    := not(RST_POLARITY_G);
45	      addra   : in  slv(ADDR_WIDTH_G-1 downto 0)                          := (others => '0');
46	      dina    : in  slv(DATA_WIDTH_G-1 downto 0)                          := (others => '0');
47	      douta   : out slv(DATA_WIDTH_G-1 downto 0);
48	      regcea  : in  sl                                                    := '1';  -- Clock enable for extra output reg. Only used when DOA_REG_G = true
49	      -- Port B
50	      clkb    : in  sl                                                    := '0';
51	      enb     : in  sl                                                    := '1';
52	      web     : in  sl                                                    := '0';
53	      webByte : in  slv(wordCount(DATA_WIDTH_G, BYTE_WIDTH_G)-1 downto 0) := (others => '0');
54	      rstb    : in  sl                                                    := not(RST_POLARITY_G);
55	      addrb   : in  slv(ADDR_WIDTH_G-1 downto 0)                          := (others => '0');
56	      dinb    : in  slv(DATA_WIDTH_G-1 downto 0)                          := (others => '0');
57	      doutb   : out slv(DATA_WIDTH_G-1 downto 0);
58	      regceb  : in  sl                                                    := '1');  -- Clock enable for extra output reg. Only used when DOA_REG_G = true
59	end TrueDualPortRam;
60	
61	architecture rtl of TrueDualPortRam is
62	
63	   -- Set byte width to word width if byte writes not enabled
64	   -- Otherwise block ram parity bits wont be utilized
65	   constant BYTE_WIDTH_C      : natural := ite(BYTE_WR_EN_G, BYTE_WIDTH_G, DATA_WIDTH_G);
66	   constant NUM_BYTES_C       : natural := wordCount(DATA_WIDTH_G, BYTE_WIDTH_C);
67	   constant FULL_DATA_WIDTH_C : natural := NUM_BYTES_C*BYTE_WIDTH_C;
68	
69	   constant INIT_C : slv(FULL_DATA_WIDTH_C-1 downto 0) := ite(INIT_G = "0", slvZero(FULL_DATA_WIDTH_C), INIT_G);
70	
71	   -- Shared memory
72	   type MemType is array ((2**ADDR_WIDTH_G)-1 downto 0) of slv(FULL_DATA_WIDTH_C-1 downto 0);
73	   shared variable mem : MemType := (others => INIT_C);
74	
75	   signal doutAInt : slv(FULL_DATA_WIDTH_C-1 downto 0) := (others => '0');
76	   signal doutBInt : slv(FULL_DATA_WIDTH_C-1 downto 0) := (others => '0');
77	
78	   signal weaByteInt : slv(weaByte'range) := (others => '0');
79	   signal webByteInt : slv(webByte'range) := (others => '0');
80	
81	   -- Attribute for XST (Xilinx Synthesizer)
82	   attribute ram_style        : string;
83	   attribute ram_style of mem : variable is "block";
84	
85	   attribute ram_extract        : string;
86	   attribute ram_extract of mem : variable is "TRUE";
87	
88	   attribute keep        : boolean;     --"keep" is same for XST and Altera
89	   attribute keep of mem : variable is true;  --"keep" is same for XST and Altera
90	
91	   -- Attribute for Synplicity Synthesizer
92	   attribute syn_ramstyle        : string;
93	   attribute syn_ramstyle of mem : variable is "block";
94	
95	   attribute syn_keep        : string;
96	   attribute syn_keep of mem : variable is "TRUE";
97	
98	begin
99	
100	   -- MODE_G check
101	   assert (MODE_G = "no-change") or (MODE_G = "read-first") or (MODE_G = "write-first")
102	      report "MODE_G must be either no-change, read-first, or write-first"
103	      severity failure;
104	
105	   weaByteInt <= weaByte when BYTE_WR_EN_G else (others => wea);
106	   webByteInt <= webByte when BYTE_WR_EN_G else (others => web);
107	
108	   -------------------------------------------------------------------------------------------------
109	   -- No Change Mode
110	   -------------------------------------------------------------------------------------------------
111	   NO_CHANGE_MODE : if MODE_G = "no-change" generate
112	      -- Port A
113	      process(clka)
114	      begin
115	         if rising_edge(clka) then
116	            if (ena = '1') then
117	               for i in 0 to NUM_BYTES_C-1 loop
118	                  if (weaByteInt(i) = '1') then
119	                     mem(conv_integer(addra))((i+1)*BYTE_WIDTH_C-1 downto i*BYTE_WIDTH_C) :=
120	                        resize(dina(minimum(DATA_WIDTH_G-1, (i+1)*BYTE_WIDTH_C-1) downto i*BYTE_WIDTH_C), BYTE_WIDTH_C);
121	                  end if;
122	               end loop;
123	            end if;
124	         end if;
125	      end process;
126	
127	      -- Vivado does crazy stupid things if output isn't broken out into its own process in
128	      -- no-change mode
129	      process (clka, rsta) is
130	      begin
131	         if (RST_ASYNC_G and rsta = RST_POLARITY_G and DOA_REG_G = false) then
132	            doutAInt <= INIT_C after TPD_G;
133	         elsif (rising_edge(clka)) then
134	            if (ena = '1' and weaByte = 0 and wea = '0') then
135	               doutAInt <= mem(conv_integer(addra)) after TPD_G;
136	            end if;
137	            if (RST_ASYNC_G = false and rsta = RST_POLARITY_G and DOA_REG_G = false) then
138	               doutAInt <= INIT_C after TPD_G;
139	            end if;
140	         end if;
141	      end process;
142	
143	      -- Port B
144	      process(clkb)
145	      begin
146	         if rising_edge(clkb) then
147	            if (enb = '1') then
148	               for i in 0 to NUM_BYTES_C-1 loop
149	                  if (webByteInt(i) = '1') then
150	                     mem(conv_integer(addrb))((i+1)*BYTE_WIDTH_C-1 downto i*BYTE_WIDTH_C) :=
151	                        resize(dinb(minimum(DATA_WIDTH_G-1, (i+1)*BYTE_WIDTH_C-1) downto i*BYTE_WIDTH_C), BYTE_WIDTH_C);
152	                  end if;
153	               end loop;
154	            end if;
155	         end if;
156	      end process;
157	
158	      process (clkb, rstb) is
159	      begin
160	         if (RST_ASYNC_G and rstb = RST_POLARITY_G and DOB_REG_G = false) then
161	            doutBInt <= INIT_C after TPD_G;
162	         elsif (rising_edge(clkb)) then
163	            if (enb = '1' and webByte = 0 and web = '0') then
164	               doutBInt <= mem(conv_integer(addrb)) after TPD_G;
165	            end if;
166	            if (RST_ASYNC_G = false and rstb = RST_POLARITY_G and DOB_REG_G = false) then
167	               doutBInt <= INIT_C after TPD_G;
168	            end if;
169	         end if;
170	      end process;
171	
172	   end generate;
173	
174	   -------------------------------------------------------------------------------------------------
175	   -- Read first mode
176	   -------------------------------------------------------------------------------------------------
177	   READ_FIRST_MODE : if MODE_G = "read-first" generate
178	      -- Port A
179	      process(clka, rsta)
180	      begin
181	         if (RST_ASYNC_G and rsta = RST_POLARITY_G and DOA_REG_G = false) then
182	            doutAInt <= INIT_C after TPD_G;
183	         elsif rising_edge(clka) then
184	            if (ena = '1') then
185	               doutAInt <= mem(conv_integer(addra)) after TPD_G;
186	               for i in 0 to NUM_BYTES_C-1 loop
187	                  if (weaByteInt(i) = '1') then
188	                     mem(conv_integer(addra))((i+1)*BYTE_WIDTH_C-1 downto i*BYTE_WIDTH_C) :=
189	                        resize(dina(minimum(DATA_WIDTH_G-1, (i+1)*BYTE_WIDTH_C-1) downto i*BYTE_WIDTH_C), BYTE_WIDTH_C);
190	                  end if;
191	               end loop;
192	            end if;
193	            if (RST_ASYNC_G = false and rsta = RST_POLARITY_G and DOA_REG_G = false) then
194	               doutAInt <= INIT_C after TPD_G;
195	            end if;
196	         end if;
197	      end process;
198	
199	      -- Port B
200	      process(clkb, rstb)
201	      begin
202	         if (RST_ASYNC_G and rstb = RST_POLARITY_G and DOB_REG_G = false) then
203	            doutBInt <= INIT_C after TPD_G;
204	         elsif rising_edge(clkb) then
205	            if (enb = '1') then
206	               doutBInt <= mem(conv_integer(addrb)) after TPD_G;
207	               for i in 0 to NUM_BYTES_C-1 loop
208	                  if (webByteInt(i) = '1') then
209	                     mem(conv_integer(addrb))((i+1)*BYTE_WIDTH_C-1 downto i*BYTE_WIDTH_C) :=
210	                        resize(dinb(minimum(DATA_WIDTH_G-1, (i+1)*BYTE_WIDTH_C-1) downto i*BYTE_WIDTH_C), BYTE_WIDTH_C);
211	                  end if;
212	               end loop;
213	            end if;
214	            if (RST_ASYNC_G = false and rstb = RST_POLARITY_G and DOB_REG_G = false) then
215	               doutBInt <= INIT_C after TPD_G;
216	            end if;
217	         end if;
218	      end process;
219	
220	   end generate;
221	
222	   -------------------------------------------------------------------------------------------------
223	   -- Write first mode
224	   -------------------------------------------------------------------------------------------------
225	   WRITE_FIRST_MODE : if MODE_G = "write-first" generate
226	      -- Port A
227	      process(clka, rsta)
228	      begin
229	         if (RST_ASYNC_G and rsta = RST_POLARITY_G and DOA_REG_G = false) then
230	            doutAInt <= INIT_C after TPD_G;
231	         elsif rising_edge(clka) then
232	            if (ena = '1') then
233	               for i in 0 to NUM_BYTES_C-1 loop
234	                  if (weaByteInt(i) = '1') then
235	                     mem(conv_integer(addra))((i+1)*BYTE_WIDTH_C-1 downto i*BYTE_WIDTH_C) :=
236	                        resize(dina(minimum(DATA_WIDTH_G-1, (i+1)*BYTE_WIDTH_C-1) downto i*BYTE_WIDTH_C), BYTE_WIDTH_C);
237	                  end if;
238	               end loop;
239	               doutAInt <= mem(conv_integer(addra)) after TPD_G;
240	            end if;
241	            if (RST_ASYNC_G = false and rsta = RST_POLARITY_G and DOA_REG_G = false) then
242	               doutAInt <= INIT_C after TPD_G;
243	            end if;
244	         end if;
245	
246	      end process;
247	
248	      -- Port B
249	      process(clkb, rstb)
250	      begin
251	         if (RST_ASYNC_G and rstb = RST_POLARITY_G and DOB_REG_G = false) then
252	            doutBInt <= INIT_C after TPD_G;
253	         elsif rising_edge(clkb) then
254	            if (enb = '1') then
255	               for i in 0 to NUM_BYTES_C-1 loop
256	                  if (webByteInt(i) = '1') then
257	                     mem(conv_integer(addrb))((i+1)*BYTE_WIDTH_C-1 downto i*BYTE_WIDTH_C) :=
258	                        resize(dinb(minimum(DATA_WIDTH_G-1, (i+1)*BYTE_WIDTH_C-1) downto i*BYTE_WIDTH_C), BYTE_WIDTH_C);
259	                  end if;
260	               end loop;
261	               doutBInt <= mem(conv_integer(addrb)) after TPD_G;
262	            end if;
263	            if (RST_ASYNC_G = false and rstb = RST_POLARITY_G and DOB_REG_G = false) then
264	               doutBInt <= INIT_C after TPD_G;
265	            end if;
266	         end if;
267	
268	      end process;
269	
270	   end generate;
271	
272	   -------------------------------------------------------------------------------------------------
273	   -- Optional data output registers
274	   -------------------------------------------------------------------------------------------------
275	   NO_DOUT_A_REG : if (not DOA_REG_G) generate
276	      douta <= doutAInt(DATA_WIDTH_G-1 downto 0);
277	   end generate NO_DOUT_A_REG;
278	
279	   DOUT_A_REG : if (DOA_REG_G) generate
280	      process (clka, rsta) is
281	      begin
282	         if (RST_ASYNC_G and rsta = RST_POLARITY_G) then
283	            douta <= (others => '0') after TPD_G;
284	         elsif (rising_edge(clka)) then
285	            if (RST_ASYNC_G = false and rsta = RST_POLARITY_G) then
286	               douta <= (others => '0') after TPD_G;
287	            elsif (regcea = '1') then
288	               douta <= doutAInt(DATA_WIDTH_G-1 downto 0) after TPD_G;
289	            end if;
290	         end if;
291	      end process;
292	   end generate DOUT_A_REG;
293	
294	   NO_DOUT_B_REG : if (not DOB_REG_G) generate
295	      doutb <= doutBInt(DATA_WIDTH_G-1 downto 0);
296	   end generate NO_DOUT_B_REG;
297	
298	   DOUT_B_REG : if (DOB_REG_G) generate
299	      process (clkb, rstb) is
300	      begin
301	         if (RST_ASYNC_G and rstb = RST_POLARITY_G) then
302	            doutb <= (others => '0') after TPD_G;
