22	use surf.StdRtlPkg.all;
23	
24	entity LutRam is
25	   generic (
26	      TPD_G          : time     := 1 ns;
27	      RST_POLARITY_G : sl       := '1';  -- '1' for active high rst, '0' for active low
28	      RST_ASYNC_G    : boolean  := false;
29	      REG_EN_G       : boolean  := true;
30	      MODE_G         : string   := "no-change";
31	      BYTE_WR_EN_G   : boolean  := false;
32	      DATA_WIDTH_G   : positive := 16;
33	      BYTE_WIDTH_G   : positive := 8;
34	      ADDR_WIDTH_G   : positive := 4;
35	      NUM_PORTS_G    : positive;
36	      INIT_G         : slv      := "0");
37	   port (
38	      -- Port A (Read/Write)
39	      clka    : in  sl                                                    := '0';
40	      en_a    : in  sl                                                    := '1';
41	      wea     : in  sl                                                    := '0';
42	      weaByte : in  slv(wordCount(DATA_WIDTH_G, BYTE_WIDTH_G)-1 downto 0) := (others => '0');
43	      rsta    : in  sl                                                    := not(RST_POLARITY_G);
44	      addra   : in  slv(ADDR_WIDTH_G-1 downto 0)                          := (others => '0');
45	      dina    : in  slv(DATA_WIDTH_G-1 downto 0)                          := (others => '0');
46	      douta   : out slv(DATA_WIDTH_G-1 downto 0);
47	      -- Port B (Read Only, NUM_PORTS_G>=2)
48	      clkb    : in  sl                                                    := '0';
49	      en_b    : in  sl                                                    := '1';
50	      rstb    : in  sl                                                    := not(RST_POLARITY_G);
51	      addrb   : in  slv(ADDR_WIDTH_G-1 downto 0)                          := (others => '0');
52	      doutb   : out slv(DATA_WIDTH_G-1 downto 0)                          := (others => '0');
53	      -- Port C (Read Only, NUM_PORTS_G>=3)
54	      en_c    : in  sl                                                    := '1';
55	      clkc    : in  sl                                                    := '0';
56	      rstc    : in  sl                                                    := not(RST_POLARITY_G);
57	      addrc   : in  slv(ADDR_WIDTH_G-1 downto 0)                          := (others => '0');
58	      doutc   : out slv(DATA_WIDTH_G-1 downto 0)                          := (others => '0');
59	      -- Port D (Read Only, NUM_PORTS_G>=4)
60	      en_d    : in  sl                                                    := '1';
61	      clkd    : in  sl                                                    := '0';
62	      rstd    : in  sl                                                    := not(RST_POLARITY_G);
63	      addrd   : in  slv(ADDR_WIDTH_G-1 downto 0)                          := (others => '0');
64	      doutd   : out slv(DATA_WIDTH_G-1 downto 0)                          := (others => '0');
65	      -- Port E (Read Only, NUM_PORTS_G>=5)
66	      en_e    : in  sl                                                    := '1';
67	      clke    : in  sl                                                    := '0';
68	      rste    : in  sl                                                    := not(RST_POLARITY_G);
69	      addre   : in  slv(ADDR_WIDTH_G-1 downto 0)                          := (others => '0');
70	      doute   : out slv(DATA_WIDTH_G-1 downto 0)                          := (others => '0');
71	      -- Port F (Read Only, NUM_PORTS_G>=6)
72	      en_f    : in  sl                                                    := '1';
73	      clkf    : in  sl                                                    := '0';
74	      rstf    : in  sl                                                    := not(RST_POLARITY_G);
75	      addrf   : in  slv(ADDR_WIDTH_G-1 downto 0)                          := (others => '0');
76	      doutf   : out slv(DATA_WIDTH_G-1 downto 0)                          := (others => '0');
77	      -- Port G (Read Only, NUM_PORTS_G>=7)
78	      en_g    : in  sl                                                    := '1';
79	      clkg    : in  sl                                                    := '0';
80	      rstg    : in  sl                                                    := not(RST_POLARITY_G);
81	      addrg   : in  slv(ADDR_WIDTH_G-1 downto 0)                          := (others => '0');
82	      doutg   : out slv(DATA_WIDTH_G-1 downto 0)                          := (others => '0');
83	      -- Port H (Read Only, NUM_PORTS_G>=8)
84	      en_h    : in  sl                                                    := '1';
85	      clkh    : in  sl                                                    := '0';
86	      rsth    : in  sl                                                    := not(RST_POLARITY_G);
87	      addrh   : in  slv(ADDR_WIDTH_G-1 downto 0)                          := (others => '0');
88	      douth   : out slv(DATA_WIDTH_G-1 downto 0)                          := (others => '0'));
89	end LutRam;
90	
91	architecture rtl of LutRam is
92	
93	   -- Initial RAM Values
94	   constant NUM_BYTES_C       : natural := wordCount(DATA_WIDTH_G, BYTE_WIDTH_G);
95	   constant FULL_DATA_WIDTH_C : natural := NUM_BYTES_C*BYTE_WIDTH_G;
96	
97	   constant INIT_C : slv(DATA_WIDTH_G-1 downto 0) := ite(INIT_G = "0", slvZero(DATA_WIDTH_G), INIT_G);
98	
99	   -- Shared memory
100	   type MemType is array ((2**ADDR_WIDTH_G)-1 downto 0) of slv(DATA_WIDTH_G-1 downto 0);
101	   signal mem : MemType := (others => INIT_C);
102	
103	   signal weaByteInt : slv(weaByte'range);
104	
105	   -- Attribute for XST (Xilinx Synthesis)
106	   attribute ram_style        : string;
107	   attribute ram_style of mem : signal is "distributed";
108	
109	   attribute ram_extract        : string;
110	   attribute ram_extract of mem : signal is "TRUE";
111	
112	   -- Attribute for Synplicity Synthesizer
113	   attribute syn_ramstyle        : string;
114	   attribute syn_ramstyle of mem : signal is "distributed";
115	
116	   attribute syn_keep        : string;
117	   attribute syn_keep of mem : signal is "TRUE";
118	
119	begin
120	
121	   -- MODE_G check
122	   assert (MODE_G = "no-change") or (MODE_G = "read-first") or (MODE_G = "write-first")
123	      report "MODE_G must be either no-change, read-first, or write-first"
124	      severity failure;
125	
126	   weaByteInt <= weaByte when BYTE_WR_EN_G else (others => wea);
127	
128	
129	   -- Port A
130	   PORT_A_NOT_REG : if (REG_EN_G = false) generate
131	
132	      process(clka)
133	      begin
134	         if rising_edge(clka) then
135	            if (en_a = '1') then
136	               for i in NUM_BYTES_C-1 downto 0 loop
137	                  if (weaByteInt(i) = '1') then
