139	                        dina(minimum(DATA_WIDTH_G-1, (i+1)*BYTE_WIDTH_G-1) downto i*BYTE_WIDTH_G);
140	                  end if;
141	               end loop;
142	            end if;
143	         end if;
144	      end process;
145	
146	      douta <= mem(conv_integer(addra));
147	
148	
149	   end generate;
